  function maskedExample(word){if(!word.example)return '';const target=word.korean.endsWith('다')&&word.korean.length>1?word.korean.slice(0,-1):word.korean;return word.example.split(target).join('＿＿＿')}
  function renderSpelling(){const word=spellingDeck[spellingIndex];$('#spellingFeedback').innerHTML='';$('#nextSpelling').hidden=true;$('#spellingInput').value='';spellingSolved=false;if(!word){$('#spellingMeaning').textContent='当前范围没有单词';$('#spellingExample').textContent='';$('#spellingExampleZh').textContent='';$('#spellingProgress').textContent='0 / 0';$('#spellingInput').disabled=true;$('#checkSpelling').disabled=true;return}$('#spellingInput').disabled=false;$('#checkSpelling').disabled=false;$('#spellingMeaning').textContent=word.chinese;$('#spellingExample').textContent=maskedExample(word);$('#spellingExampleZh').textContent=word.exampleZh;$('#spellingProgress').textContent=`${spellingIndex+1} / ${spellingDeck.length}`;setTimeout(()=>$('#spellingInput').focus(),0)}
  function spellingDiff(input,answer){const typed=[...input],correct=[...answer],length=Math.max(typed.length,correct.length);return `<div class="char-diff">${Array.from({length},(_,index)=>{const expected=correct[index],actual=typed[index];if(expected===actual)return `<span>${esc(actual)}</span>`;if(actual===undefined)return `<span class="missing">${esc(expected)}</span>`;return `<span class="wrong" title="应为 ${esc(expected||'空')}">${esc(actual)}</span>`}).join('')}</div>`}
  function checkSpelling(){const current=spellingDeck[spellingIndex],word=current&&state.words.find(item=>item.id===current.id);if(!word||spellingSolved)return;const input=$('#spellingInput').value.trim().normalize('NFC'),answer=word.korean.normalize('NFC'),correct=input===answer;recordVocabAttempt(word,'spelling',correct);save(false);if(correct){spellingSolved=true;$('#spellingFeedback').innerHTML=`<p class="correct-text">拼写正确：${esc(word.korean)}</p>`;$('#nextSpelling').hidden=false;$('#checkSpelling').disabled=true}else{$('#spellingFeedback').innerHTML=`<p class="wrong-text">拼写不正确，可以继续重试。</p>${spellingDiff(input,answer)}<p>正确答案：<strong>${esc(word.korean)}</strong></p>`}renderWords();renderWrongWords()}
